import{_ as a,o as i,c as t,a2 as s}from"./chunks/framework.C_beXv0I.js";const u=JSON.parse('{"title":"Pipelines","description":"","frontmatter":{},"headers":[],"relativePath":"reference/pipelines.md","filePath":"reference/pipelines.md","lastUpdated":1783011651000}'),o={name:"reference/pipelines.md"};function n(r,e,l,p,d,c){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="pipelines" tabindex="-1">Pipelines <a class="header-anchor" href="#pipelines" aria-label="Permalink to &quot;Pipelines&quot;">​</a></h1><p>A pipeline is a phased, gated recipe for producing one kind of artifact. Each pipeline declares a <code>domain</code>, an ordered list of <code>phases</code> (each phase names a <code>role</code>), and a <code>gate</code>. Pipelines live as YAML in <code>pipelines/</code> and cover both software and knowledge work.</p><h2 id="routing" tabindex="-1">Routing <a class="header-anchor" href="#routing" aria-label="Permalink to &quot;Routing&quot;">​</a></h2><p>Routing to a pipeline is deterministic. <code>muster route &quot;&lt;outcome&gt;&quot;</code> matches the outcome against each pipeline&#39;s <code>match</code> keywords on word boundaries; if nothing matches, it falls back to the domain default.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;draft a PRD for a referral program&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pipeline</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prd</span></span></code></pre></div><h2 id="the-gate-a-floor-principle" tabindex="-1">The gate: a floor principle <a class="header-anchor" href="#the-gate-a-floor-principle" aria-label="Permalink to &quot;The gate: a floor principle&quot;">​</a></h2><p>Gating uses a <strong>floor principle</strong>: the weakest dimension must clear the gate&#39;s floor, and the total must clear a pass threshold. A strong average cannot rescue one weak dimension. Scoring is deterministic and fails loud on non-finite inputs. The model only estimates the per-dimension scores; the code decides pass or fail.</p><h2 id="humanize" tabindex="-1">Humanize <a class="header-anchor" href="#humanize" aria-label="Permalink to &quot;Humanize&quot;">​</a></h2><p>Human-facing pipelines end with a <code>humanize</code> phase. The <code>muster-humanizer</code> built-in strips em-dashes, banned AI-tell words, and robotic cadence. Machine-facing AI specs (the implementation-spec and test-plan pipelines) are exempt, to preserve technical precision.</p><h2 id="the-set" tabindex="-1">The set <a class="header-anchor" href="#the-set" aria-label="Permalink to &quot;The set&quot;">​</a></h2><p>The catalog spans software and knowledge work:</p><ul><li><strong>Product</strong>: PRD, epic, user-story, roadmap</li><li><strong>Business</strong>: business-case, executive-summary, OKRs, competitive-battlecard</li><li><strong>Launch and comms</strong>: launch-plan, release-notes, case-study</li><li><strong>Content</strong>: blog-post, social-post, newsletter, lead-magnet, book (fiction and non-fiction)</li><li><strong>Engineering specs</strong>: AI implementation spec, AI test plan</li><li><strong>Operations</strong>: runbook</li></ul><h2 id="roadmap-prioritization" tabindex="-1">Roadmap prioritization <a class="header-anchor" href="#roadmap-prioritization" aria-label="Permalink to &quot;Roadmap prioritization&quot;">​</a></h2><p>One pipeline worth calling out. Goals go in, a prioritized now/next/later roadmap comes out. The model estimates the factors with evidence-backed rationale; <code>muster prioritize</code> does the arithmetic and fails loud on bad input. RICE is the default, with <code>ice</code>, <code>wsjf</code>, and <code>weighted</code> also available. See <a href="/muster/reference/commands#prioritization-models">prioritization models</a>.</p><p>The roadmap skill can render the ranking to a doc, optionally file the top-N initiatives as GitHub issues, and optionally push them onto a GitHub Project board with status columns by tier. Each external step degrades gracefully, skipping with a note when <code>gh</code> access is unavailable.</p><p>Next: the full <a href="/muster/reference/architecture">Architecture</a>.</p>`,16)])])}const m=a(o,[["render",n]]);export{u as __pageData,m as default};
